func executionDecisionForAudit(report ExecuteBeadReport, finalDecision string) string {
	if decision := strings.TrimSpace(report.ExecutionDecision); decision != "" {
		return decision
	}
	if decomposedParentAudit(report) {
		return "execution_ineligible"
	}
	status := firstNonEmpty(strings.TrimSpace(finalDecision), report.Status)
	switch status {
	case ExecuteBeadStatusDeclinedNeedsDecomposition, ExecuteBeadStatusLandOperatorAttention,
		ExecuteBeadStatusLandConflictOperatorRequired, ExecuteBeadStatusReviewBlock,
		ExecuteBeadStatusReviewRequestClarification, ExecuteBeadStatusPreservedNeedsReview:
		return "proposed"
	default:
		return ""
	}
}

func decomposedParentAudit(report ExecuteBeadReport) bool {
	switch strings.TrimSpace(report.OutcomeReason) {
	case "decomposed", "too_large_decomposed":
		return true
	default:
		return strings.TrimSpace(report.ExecutionDecision) == "execution_ineligible" && len(report.DecomposedChildIDs) > 0
	}
}

func reviewAuditStatus(report ExecuteBeadReport, reviewPresent bool, reviewVerdict string) (string, string) {
	if strings.TrimSpace(report.ReviewSkipReason) != "" {
		return "skipped", strings.TrimSpace(report.ReviewSkipReason)
	}
	if reviewPresent || len(report.ReviewVerdictsFromTrace()) > 0 {
		if strings.TrimSpace(reviewVerdict) == "" {
			return "malformed", ""
		}
		return "completed", ""
	}
	if strings.TrimSpace(report.ReviewVerdict) != "" {
		return "completed", ""
	}
	if report.Status == ExecuteBeadStatusReviewMalfunction {
		return "malformed", ""
	}
	return "skipped", "review_not_configured"
}

func reviewClassificationForAudit(report ExecuteBeadReport, reviewStatus string) string {
	if class := strings.TrimSpace(report.FirstReviewClassificationFromTrace()); class != "" {
		return class
	}
	switch reviewStatus {
	case "malformed":
		return ReviewFindingClassMalfunction
	case "skipped":
		return "review_skipped"
	default:
		return "review_completed"
	}
}

func landStatusForAudit(report ExecuteBeadReport, finalDecision string) string {
	status := firstNonEmpty(strings.TrimSpace(finalDecision), report.Status)
	if strings.Contains(strings.ToLower(report.Detail), "land coordination reconciled") {
		return "reconciled"
	}
	switch status {
	case ExecuteBeadStatusSuccess, ExecuteBeadStatusAlreadySatisfied:
		if report.ResultRev == "" && report.LandedRev == "" {
			return "not_applicable"
		}
		return "landed"
	case ExecuteBeadStatusLandRetry:
		return "retry"
	case ExecuteBeadStatusLandOperatorAttention:
		return "operator_attention"
	case ExecuteBeadStatusLandConflict, ExecuteBeadStatusLandConflictUnresolvable, ExecuteBeadStatusLandConflictOperatorRequired:
		return "conflict"
	default:
		return "not_landed"
	}
}

func reconcileStatusForAudit(report ExecuteBeadReport) string {
	detail := strings.ToLower(report.Detail + "\n" + report.OutcomeReason)
	switch {
	case strings.Contains(detail, "land coordination reconciled"):
		return "reconciled"
	case report.Status == ExecuteBeadStatusLandRetry:
		return "pending"
	default:
		return "not_applicable"
	}
}

