// interactive single-bead CLI), the generated preserve ref matches the
// documented pattern refs/ddx/iterations/<bead-id>/<ts>-<sha>.
func TestLandBeadResult_PreserveRefFormat(t *testing.T) {
	projectRoot := t.TempDir()
